export interface AuthorityQuestion {
  id: number;
  question: string;
  options: string[];
  correctAnswer: string;
  rationale: string;
  category: string;
  difficulty: "Easy" | "Medium" | "Hard";
}

export interface AuthoritySection {
  id: string;
  title: string;
  content: string;
}

export interface AuthorityContentPage {
  slug: string;
  professionSlug: string;
  canonicalPath: string;
  pageType: "top-questions" | "ultimate-guide";
  title: string;
  subtitle: string;
  metaTitle: string;
  metaDescription: string;
  keywords: string;
  color: string;
  colorAccent: string;
  colorGradientFrom: string;
  colorGradientTo: string;
  icon: string;
  introduction: string;
  sections: AuthoritySection[];
  practiceQuestions: AuthorityQuestion[];
  keyConcepts: { title: string; description: string }[];
  relatedLinks: { label: string; href: string; type: string }[];
  ctaPrimary: { label: string; href: string };
  ctaSecondary: { label: string; href: string };
}

function generateNursingQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A client with heart failure is receiving furosemide (Lasix) 40mg IV. Which laboratory value should the nurse monitor most closely?", options: ["A. Potassium level", "B. Calcium level", "C. Sodium level", "D. Magnesium level"], correctAnswer: "A", rationale: "Furosemide is a loop diuretic that causes significant potassium loss. Hypokalemia can lead to cardiac dysrhythmias, muscle weakness, and digoxin toxicity. While other electrolytes may also be affected, potassium is the priority concern.", category: "Pharmacology", difficulty: "Easy" },
    { id: 2, question: "A nurse is caring for a client with diabetic ketoacidosis (DKA). Which assessment finding would the nurse expect?", options: ["A. Kussmaul respirations", "B. Bradycardia", "C. Hypertension", "D. Weight gain"], correctAnswer: "A", rationale: "Kussmaul respirations (deep, rapid breathing) are a compensatory mechanism in DKA. The body attempts to blow off excess CO2 to counteract the metabolic acidosis caused by ketone accumulation.", category: "Medical-Surgical", difficulty: "Medium" },
    { id: 3, question: "A client is receiving a blood transfusion and develops fever, chills, and flank pain 15 minutes after the transfusion begins. What is the nurse's priority action?", options: ["A. Slow the transfusion rate", "B. Stop the transfusion immediately", "C. Administer acetaminophen", "D. Obtain a urine specimen"], correctAnswer: "B", rationale: "These symptoms suggest an acute hemolytic transfusion reaction, which is a life-threatening emergency. The first priority is to stop the transfusion immediately to prevent further infusion of incompatible blood.", category: "Medical-Surgical", difficulty: "Medium" },
    { id: 4, question: "Which client should the nurse assess first after receiving shift report?", options: ["A. A client with pneumonia who has a temperature of 38.3°C (101°F)", "B. A client post-appendectomy who reports pain of 6/10", "C. A client with COPD whose oxygen saturation is 88%", "D. A client with chest pain and new ST-segment elevation"], correctAnswer: "D", rationale: "New ST-segment elevation with chest pain indicates an acute myocardial infarction (STEMI), which is a life-threatening emergency requiring immediate intervention. The other findings, while needing attention, are expected or non-emergent.", category: "Prioritization", difficulty: "Hard" },
    { id: 5, question: "A nurse is teaching a client about warfarin (Coumadin). Which statement by the client indicates a need for further teaching?", options: ["A. 'I will have regular blood tests to check my INR.'", "B. 'I should eat consistent amounts of green leafy vegetables.'", "C. 'I can take aspirin for headaches while on this medication.'", "D. 'I will use an electric razor instead of a straight razor.'"], correctAnswer: "C", rationale: "Taking aspirin with warfarin significantly increases bleeding risk because both medications affect clotting. Aspirin inhibits platelet function while warfarin inhibits clotting factor synthesis. This combination requires medical supervision.", category: "Pharmacology", difficulty: "Easy" },
    { id: 6, question: "A client with cirrhosis develops ascites. Which dietary modification should the nurse recommend?", options: ["A. High-protein, high-calorie diet", "B. Sodium-restricted diet", "C. High-fiber diet", "D. Potassium-restricted diet"], correctAnswer: "B", rationale: "Ascites in cirrhosis results from portal hypertension and decreased albumin production, leading to fluid accumulation. Sodium restriction (typically 2g/day) helps reduce fluid retention. Excess sodium causes water retention, worsening ascites.", category: "Medical-Surgical", difficulty: "Medium" },
    { id: 7, question: "A nurse is caring for a client in active labor. The fetal heart rate tracing shows late decelerations. What is the appropriate nursing intervention?", options: ["A. Continue to monitor the pattern", "B. Reposition the client to the left lateral position", "C. Increase the oxytocin infusion rate", "D. Encourage the client to push with contractions"], correctAnswer: "B", rationale: "Late decelerations indicate uteroplacental insufficiency — the placenta is not adequately supplying oxygen to the fetus. Repositioning to the left lateral position maximizes placental blood flow by relieving pressure on the vena cava.", category: "Maternal-Newborn", difficulty: "Medium" },
    { id: 8, question: "A client with chronic kidney disease has a potassium level of 6.2 mEq/L. Which ECG change would the nurse anticipate?", options: ["A. Flattened T waves", "B. Tall, peaked T waves", "C. Prolonged QT interval", "D. ST-segment depression"], correctAnswer: "B", rationale: "Hyperkalemia (K+ > 5.0 mEq/L) causes characteristic tall, peaked T waves on ECG. As potassium continues to rise, it can progress to widened QRS complexes, absent P waves, and eventually ventricular fibrillation.", category: "Medical-Surgical", difficulty: "Hard" },
    { id: 9, question: "A nurse is preparing to administer medications to four clients. Which medication should the nurse question before administering?", options: ["A. Metformin to a client with a blood glucose of 180 mg/dL", "B. Atenolol to a client with a heart rate of 52 bpm", "C. Lisinopril to a client with a blood pressure of 138/88 mmHg", "D. Levothyroxine to a client with a TSH of 8.2 mIU/L"], correctAnswer: "B", rationale: "Beta-blockers like atenolol should be held and the prescriber notified when the heart rate is below 60 bpm. Administering a beta-blocker to a bradycardic client could cause dangerously low heart rate and cardiac output.", category: "Pharmacology", difficulty: "Medium" },
    { id: 10, question: "A nurse is caring for a newborn 12 hours after birth. Which finding requires immediate intervention?", options: ["A. Respiratory rate of 42 breaths/min", "B. Acrocyanosis of hands and feet", "C. Projectile vomiting of bile-stained fluid", "D. Passage of meconium stool"], correctAnswer: "C", rationale: "Bile-stained (green) projectile vomiting in a newborn is a sign of intestinal obstruction (such as volvulus or duodenal atresia) and is a surgical emergency. The other findings are normal for a 12-hour-old newborn.", category: "Maternal-Newborn", difficulty: "Hard" },
    { id: 11, question: "A client with type 1 diabetes has a blood glucose of 52 mg/dL and is conscious but confused. What is the nurse's priority action?", options: ["A. Administer glucagon IM", "B. Give 4 oz of orange juice with sugar", "C. Start a D5W IV infusion", "D. Recheck the blood glucose in 15 minutes"], correctAnswer: "B", rationale: "For a conscious client with hypoglycemia, the priority is to provide fast-acting oral glucose. Orange juice with sugar provides rapid carbohydrate absorption. Glucagon is reserved for unconscious clients who cannot swallow safely.", category: "Medical-Surgical", difficulty: "Easy" },
    { id: 12, question: "A nurse is assessing a client 2 hours after a right total knee replacement. Which finding indicates a potential complication?", options: ["A. Pain rated 5/10 with movement", "B. Moderate serosanguineous drainage on the dressing", "C. Inability to dorsiflex the right foot", "D. Mild swelling around the surgical site"], correctAnswer: "C", rationale: "Inability to dorsiflex the foot after knee replacement may indicate peroneal nerve damage or compartment syndrome. This neurovascular compromise requires immediate assessment and notification of the surgeon.", category: "Medical-Surgical", difficulty: "Hard" },
    { id: 13, question: "A client is admitted with suspected meningitis. Which assessment findings would support this diagnosis? (Select all that apply.)", options: ["A. Positive Brudzinski's sign", "B. Photophobia", "C. Nuchal rigidity", "D. Bradycardia", "E. Petechial rash"], correctAnswer: "A, B, C, E", rationale: "Meningitis presents with nuchal rigidity, positive Brudzinski's sign (neck flexion causes hip/knee flexion), photophobia, and petechial rash (especially with meningococcal meningitis). Tachycardia, not bradycardia, is expected.", category: "Medical-Surgical", difficulty: "Medium" },
    { id: 14, question: "A nurse is planning discharge teaching for a client taking phenytoin (Dilantin). Which instruction is most important?", options: ["A. 'Take the medication with antacids to prevent stomach upset.'", "B. 'Maintain good oral hygiene and see your dentist regularly.'", "C. 'You may discontinue the medication when seizures stop.'", "D. 'Drink grapefruit juice to enhance absorption.'"], correctAnswer: "B", rationale: "Phenytoin commonly causes gingival hyperplasia (overgrowth of gum tissue). Meticulous oral hygiene and regular dental visits help manage this side effect. Phenytoin should never be abruptly discontinued as this can trigger status epilepticus.", category: "Pharmacology", difficulty: "Easy" },
    { id: 15, question: "A nurse is caring for a client with a chest tube connected to a water-seal drainage system. Which observation requires immediate action?", options: ["A. Continuous bubbling in the water-seal chamber", "B. Tidaling (fluctuation) in the water-seal chamber during breathing", "C. 50 mL of serosanguineous drainage in the collection chamber over 4 hours", "D. The drainage system is positioned below the level of the client's chest"], correctAnswer: "A", rationale: "Continuous bubbling in the water-seal chamber indicates an air leak in the system. This could be from a loose connection, a break in the tubing, or a persistent pneumothorax. The nurse should systematically check all connections and notify the provider.", category: "Medical-Surgical", difficulty: "Hard" },
  ];
}

function generateParamedicQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A 55-year-old male presents with crushing substernal chest pain radiating to his left arm and jaw. His vitals are BP 90/60, HR 110, RR 24, SpO2 94%. What is your priority intervention?", options: ["A. Obtain a 12-lead ECG", "B. Establish IV access and administer a fluid bolus", "C. Administer aspirin 160-325mg chewed", "D. Apply high-flow oxygen via non-rebreather mask"], correctAnswer: "C", rationale: "Aspirin inhibits platelet aggregation and has been shown to significantly reduce mortality in acute coronary syndromes. While all listed interventions are important, aspirin should be administered early to prevent further thrombus formation.", category: "Cardiac Emergencies", difficulty: "Medium" },
    { id: 2, question: "You arrive on scene to find a 4-year-old child with stridor, drooling, and sitting in the 'tripod' position. The child has a fever of 39.5°C. What is the most likely diagnosis?", options: ["A. Croup", "B. Epiglottitis", "C. Foreign body aspiration", "D. Asthma exacerbation"], correctAnswer: "B", rationale: "The classic presentation of epiglottitis includes the 3 D's: Drooling, Dysphagia, and Distress. The tripod position, high fever, and stridor in a young child strongly suggest epiglottitis. Unlike croup, epiglottitis has an acute onset and higher fever.", category: "Pediatric Emergencies", difficulty: "Medium" },
    { id: 3, question: "A trauma patient has paradoxical chest wall movement, severe dyspnea, and crepitus over the left thorax. What condition do you suspect?", options: ["A. Simple pneumothorax", "B. Tension pneumothorax", "C. Flail chest", "D. Cardiac tamponade"], correctAnswer: "C", rationale: "Paradoxical chest wall movement (segment moves inward on inspiration and outward on expiration) is the hallmark of flail chest, caused by two or more adjacent ribs fractured in two or more places. Crepitus confirms rib fractures.", category: "Trauma", difficulty: "Hard" },
    { id: 4, question: "A 28-year-old female was stung by a bee and is now experiencing generalized urticaria, wheezing, facial swelling, and hypotension. What is the first-line medication?", options: ["A. Diphenhydramine 50mg IV", "B. Epinephrine 0.3mg IM", "C. Methylprednisolone 125mg IV", "D. Albuterol 2.5mg nebulized"], correctAnswer: "B", rationale: "Epinephrine is the first-line treatment for anaphylaxis. It addresses all life-threatening symptoms: bronchospasm (beta-2 effects), hypotension (alpha-1 vasoconstriction), and urticaria/angioedema (mast cell stabilization). Delay in epinephrine administration increases mortality risk.", category: "Medical Emergencies", difficulty: "Easy" },
    { id: 5, question: "You are ventilating a cardiac arrest patient and notice increasing resistance to bag-valve-mask ventilation and absent breath sounds on the right side. What should you suspect?", options: ["A. Bronchospasm", "B. Right mainstem intubation", "C. Tension pneumothorax", "D. Equipment malfunction"], correctAnswer: "C", rationale: "During CPR, tension pneumothorax can develop from rib fractures or aggressive ventilation. Progressive ventilation difficulty with unilateral absent breath sounds is classic. Needle decompression at the 2nd intercostal space, midclavicular line, is indicated.", category: "Cardiac Arrest", difficulty: "Hard" },
    { id: 6, question: "What is the initial energy setting for synchronized cardioversion of unstable supraventricular tachycardia (SVT) in an adult?", options: ["A. 50-100 J biphasic", "B. 120-200 J biphasic", "C. 200 J biphasic", "D. 360 J monophasic"], correctAnswer: "A", rationale: "Synchronized cardioversion for SVT begins at 50-100 joules biphasic. The narrow QRS complex of SVT requires less energy than ventricular tachycardia. Always ensure the defibrillator is in synchronized (SYNC) mode to deliver the shock coinciding with the R wave.", category: "Cardiac Emergencies", difficulty: "Medium" },
    { id: 7, question: "A patient has been pulled from a house fire with facial burns, singed nasal hairs, and carbonaceous sputum. What is your primary concern?", options: ["A. Carbon monoxide poisoning", "B. Cyanide toxicity", "C. Inhalation injury with impending airway compromise", "D. Third-degree facial burns"], correctAnswer: "C", rationale: "Facial burns, singed nasal hairs, and carbonaceous sputum are signs of inhalation injury. The primary concern is progressive airway edema that can rapidly occlude the airway. Early intubation should be considered before swelling makes it impossible.", category: "Trauma", difficulty: "Hard" },
    { id: 8, question: "A 70-year-old male has a GCS of 8, unequal pupils (left dilated and fixed), and left-sided hemiparesis. What is the most likely diagnosis?", options: ["A. Right-sided hemorrhagic stroke", "B. Left-sided epidural hematoma", "C. Metabolic encephalopathy", "D. Posterior circulation stroke"], correctAnswer: "A", rationale: "A right-sided hemorrhagic stroke causes contralateral (left) hemiparesis and ipsilateral pupil changes due to uncal herniation compressing the oculomotor nerve. The low GCS indicates significant intracranial pathology requiring emergent transport.", category: "Neurological Emergencies", difficulty: "Hard" },
    { id: 9, question: "Which rhythm requires defibrillation as part of the cardiac arrest algorithm?", options: ["A. Pulseless electrical activity (PEA)", "B. Asystole", "C. Ventricular fibrillation", "D. Third-degree heart block with a pulse"], correctAnswer: "C", rationale: "Ventricular fibrillation (VF) and pulseless ventricular tachycardia (pVT) are the two shockable rhythms in cardiac arrest. PEA and asystole are non-shockable and are treated with CPR and epinephrine. Early defibrillation for VF is the single most important intervention.", category: "Cardiac Arrest", difficulty: "Easy" },
    { id: 10, question: "A motorcyclist is found lying in the road after a collision at 60 km/h. He is alert but complains of severe neck pain. What is the appropriate spinal motion restriction approach?", options: ["A. Apply a cervical collar and secure to a long backboard", "B. Allow the patient to self-extricate and sit upright", "C. Apply a cervical collar only if neurological deficits are present", "D. Place in recovery position without spinal precautions"], correctAnswer: "A", rationale: "High-mechanism trauma with neck pain meets criteria for spinal motion restriction. A cervical collar with long backboard immobilization is appropriate for this mechanism. The speed of impact and complaint of neck pain indicate high risk for spinal injury.", category: "Trauma", difficulty: "Easy" },
  ];
}

function generateRrtQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A patient on mechanical ventilation has the following ABG results: pH 7.28, PaCO2 58 mmHg, HCO3 24 mEq/L, PaO2 72 mmHg. What is the primary acid-base disturbance?", options: ["A. Respiratory acidosis", "B. Metabolic acidosis", "C. Respiratory alkalosis", "D. Mixed acid-base disorder"], correctAnswer: "A", rationale: "The pH < 7.35 indicates acidosis. The PaCO2 is elevated (>45 mmHg) indicating respiratory origin. The HCO3 is normal (22-26), suggesting acute respiratory acidosis without metabolic compensation. The ventilator settings need adjustment — increase tidal volume or respiratory rate.", category: "ABG Interpretation", difficulty: "Easy" },
    { id: 2, question: "A COPD patient is being treated with bilevel positive airway pressure (BiPAP). The settings are IPAP 12 cmH2O and EPAP 5 cmH2O. What is the driving pressure (pressure support)?", options: ["A. 5 cmH2O", "B. 7 cmH2O", "C. 12 cmH2O", "D. 17 cmH2O"], correctAnswer: "B", rationale: "Driving pressure (pressure support) = IPAP - EPAP = 12 - 5 = 7 cmH2O. This is the effective pressure that augments the patient's tidal volume. Increasing the gap between IPAP and EPAP increases ventilatory support.", category: "Mechanical Ventilation", difficulty: "Easy" },
    { id: 3, question: "A neonate born at 28 weeks gestation develops progressive respiratory distress with grunting, nasal flaring, and intercostal retractions. Chest X-ray shows bilateral ground-glass opacities. What is the most likely diagnosis?", options: ["A. Meconium aspiration syndrome", "B. Neonatal respiratory distress syndrome (RDS)", "C. Transient tachypnea of the newborn", "D. Congenital diaphragmatic hernia"], correctAnswer: "B", rationale: "Premature neonates lack adequate surfactant production, leading to RDS. Ground-glass opacities with air bronchograms on CXR are characteristic. Treatment includes surfactant replacement therapy, CPAP, and mechanical ventilation as needed.", category: "Neonatal Respiratory Care", difficulty: "Medium" },
    { id: 4, question: "A ventilated patient's peak inspiratory pressure (PIP) has increased from 25 to 42 cmH2O while plateau pressure remains at 20 cmH2O. What is the most likely cause?", options: ["A. Decreased lung compliance", "B. Increased airway resistance", "C. Patient-ventilator dyssynchrony", "D. Auto-PEEP"], correctAnswer: "B", rationale: "When PIP increases but plateau pressure remains unchanged, the problem is increased airway resistance (the difference between PIP and Pplat reflects resistance). Common causes include bronchospasm, mucus plugging, or ETT obstruction. Decreased compliance would raise both PIP and plateau pressure.", category: "Mechanical Ventilation", difficulty: "Hard" },
    { id: 5, question: "Which of the following pulmonary function test results is most consistent with a restrictive lung disease pattern?", options: ["A. Decreased FEV1/FVC ratio", "B. Normal FEV1/FVC ratio with decreased TLC", "C. Increased RV/TLC ratio", "D. Decreased FEV1 with normal FVC"], correctAnswer: "B", rationale: "Restrictive lung diseases (pulmonary fibrosis, chest wall deformity) show reduced lung volumes (TLC, VC, FRC) with a normal or elevated FEV1/FVC ratio (≥70%). The hallmark is that all volumes are proportionally reduced.", category: "Pulmonary Function Testing", difficulty: "Medium" },
    { id: 6, question: "A patient with ARDS is being ventilated with the following settings: Vt 6 mL/kg IBW, RR 28, FiO2 100%, PEEP 16 cmH2O. The PaO2 is 55 mmHg. What is the next appropriate intervention?", options: ["A. Increase tidal volume to 10 mL/kg", "B. Initiate prone positioning", "C. Add an inhaled vasodilator", "D. Decrease PEEP to reduce barotrauma risk"], correctAnswer: "B", rationale: "With refractory hypoxemia despite high PEEP and 100% FiO2, prone positioning is indicated per ARDSNet protocol. Proning improves V/Q matching by redistributing ventilation to previously dependent lung regions. Increasing Vt would violate lung-protective ventilation.", category: "ARDS Management", difficulty: "Hard" },
    { id: 7, question: "What is the normal oxygen consumption index (VO2I) for an adult at rest?", options: ["A. 100-120 mL/min/m²", "B. 120-160 mL/min/m²", "C. 200-250 mL/min/m²", "D. 300-350 mL/min/m²"], correctAnswer: "B", rationale: "Normal VO2 index ranges from 120-160 mL/min/m². This represents the body's oxygen utilization rate indexed to body surface area. Elevated values indicate increased metabolic demand (sepsis, burns), while decreased values may indicate cellular dysfunction or decreased oxygen delivery.", category: "Hemodynamics", difficulty: "Medium" },
    { id: 8, question: "A patient on volume-control ventilation develops high-pressure alarms. The respiratory therapist performs suctioning and obtains a large amount of thick, yellow secretions. What should the RT do next?", options: ["A. Increase the high-pressure alarm limit", "B. Administer a bronchodilator and reassess", "C. Recommend a chest X-ray and continue monitoring", "D. Instill normal saline before suctioning again"], correctAnswer: "B", rationale: "After clearing secretions, administering a bronchodilator helps relieve any bronchospasm caused by irritation and prevents further airway obstruction. Reassessment of pressures after bronchodilator helps determine if the issue is resolved. Instilling saline is not evidence-based practice.", category: "Airway Management", difficulty: "Easy" },
    { id: 9, question: "A patient receiving 28% oxygen via Venturi mask has a PaO2 of 58 mmHg and SpO2 of 88%. The physician orders an increase to 35% O2. What is the approximate air-to-oxygen entrainment ratio for a 35% Venturi mask?", options: ["A. 3.6:1", "B. 5.1:1", "C. 6.2:1", "D. 8:1"], correctAnswer: "B", rationale: "The air-to-oxygen entrainment ratio for 35% FiO2 is approximately 5.1:1 (5.1 parts air to 1 part oxygen). This is calculated using the air entrainment formula. The Venturi mask provides precise, fixed FiO2 regardless of the patient's breathing pattern.", category: "Oxygen Therapy", difficulty: "Medium" },
    { id: 10, question: "During a spontaneous breathing trial (SBT), which finding indicates the patient is failing and should be placed back on full ventilatory support?", options: ["A. Respiratory rate of 20 breaths/min", "B. Heart rate increase of 15 bpm from baseline", "C. Respiratory rate > 35 with accessory muscle use and diaphoresis", "D. SpO2 of 94% on room air"], correctAnswer: "C", rationale: "SBT failure criteria include: RR > 35 or < 8, SpO2 < 88%, HR change > 20%, systolic BP > 180 or < 90, accessory muscle use, diaphoresis, or paradoxical breathing. These signs indicate the patient cannot sustain independent breathing.", category: "Ventilator Weaning", difficulty: "Medium" },
  ];
}

function generateMltQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A blood bank technologist discovers that a patient's crossmatch is incompatible. The antibody screen is positive with anti-Kell antibodies. Which of the following blood units would be compatible?", options: ["A. Kell-positive, crossmatch compatible", "B. Kell-negative, crossmatch compatible", "C. Any ABO-compatible unit", "D. Autologous donation only"], correctAnswer: "B", rationale: "When a patient has anti-Kell antibodies, only Kell-negative (K-negative) donor units should be selected. The crossmatch must also be compatible. Kell-positive units will cause a hemolytic transfusion reaction in a sensitized patient.", category: "Blood Banking", difficulty: "Medium" },
    { id: 2, question: "A CBC shows: WBC 2.1 × 10⁹/L, RBC 2.8 × 10¹²/L, Hgb 85 g/L, Plt 45 × 10⁹/L. This pattern of pancytopenia is most consistent with:", options: ["A. Iron deficiency anemia", "B. Aplastic anemia", "C. Chronic lymphocytic leukemia", "D. Polycythemia vera"], correctAnswer: "B", rationale: "Pancytopenia (decreased WBCs, RBCs, and platelets) is the hallmark of aplastic anemia, a condition where the bone marrow fails to produce adequate blood cells. Iron deficiency affects only the red cell line, while CLL causes elevated WBCs.", category: "Hematology", difficulty: "Medium" },
    { id: 3, question: "Which organism would appear as Gram-positive cocci in clusters and produce a positive coagulase test?", options: ["A. Streptococcus pneumoniae", "B. Staphylococcus aureus", "C. Enterococcus faecalis", "D. Staphylococcus epidermidis"], correctAnswer: "B", rationale: "Staphylococcus aureus is the only common Gram-positive coccus that is coagulase-positive. This key biochemical test differentiates S. aureus from coagulase-negative staphylococci (like S. epidermidis). Streptococci appear in chains, not clusters.", category: "Microbiology", difficulty: "Easy" },
    { id: 4, question: "A patient's chemistry panel shows: Na⁺ 128 mEq/L, K⁺ 5.8 mEq/L, Cl⁻ 98 mEq/L, CO₂ 18 mEq/L, BUN 45 mg/dL, Creatinine 4.2 mg/dL. These results are most consistent with:", options: ["A. Diabetic ketoacidosis", "B. Acute renal failure", "C. Addison's disease", "D. Hepatorenal syndrome"], correctAnswer: "B", rationale: "Elevated BUN and creatinine with hyperkalemia, hyponatremia, and low CO₂ (metabolic acidosis) are classic for acute renal failure. The kidneys cannot excrete potassium and waste products, and sodium is diluted by fluid retention.", category: "Clinical Chemistry", difficulty: "Medium" },
    { id: 5, question: "The order of draw for vacuum blood collection tubes is:", options: ["A. Lavender → Red → Blue → Green", "B. Blue → Red → Green → Lavender", "C. Red → Blue → Green → Lavender", "D. Blue → Gold → Green → Lavender"], correctAnswer: "D", rationale: "The correct order of draw is: Blood cultures → Light blue (citrate) → Red/Gold (SST) → Green (heparin) → Lavender (EDTA) → Gray (fluoride). This sequence prevents additive carryover that could affect test results.", category: "Specimen Collection", difficulty: "Easy" },
    { id: 6, question: "Which hemoglobin electrophoresis pattern is characteristic of sickle cell disease (HbSS)?", options: ["A. HbA 97%, HbA2 2.5%, HbF 0.5%", "B. HbS 80-90%, HbF 5-15%, HbA absent", "C. HbA 55-60%, HbS 35-40%, HbF 1%", "D. HbA 95%, HbS 5%"], correctAnswer: "B", rationale: "In sickle cell disease (homozygous HbSS), HbA is absent because both beta-globin genes produce HbS. HbS predominates at 80-90% with variable HbF (fetal hemoglobin). Sickle cell trait (HbAS) would show both HbA and HbS.", category: "Hematology", difficulty: "Hard" },
    { id: 7, question: "A urinalysis shows: pH 8.5, protein 2+, nitrite positive, leukocyte esterase positive, WBC > 50/HPF, bacteria many. These findings are most consistent with:", options: ["A. Glomerulonephritis", "B. Nephrotic syndrome", "C. Urinary tract infection", "D. Renal calculi"], correctAnswer: "C", rationale: "Positive nitrites (bacterial reduction of nitrates), positive leukocyte esterase, elevated WBCs, and many bacteria are classic indicators of UTI. The alkaline pH may result from urea-splitting organisms like Proteus species.", category: "Urinalysis", difficulty: "Easy" },
    { id: 8, question: "In quality control, when a Levy-Jennings chart shows 7 consecutive data points above the mean, this is called:", options: ["A. A shift (Westgard 7x rule violation)", "B. A trend", "C. Random error", "D. Normal variation"], correctAnswer: "A", rationale: "Seven consecutive points on one side of the mean violates the Westgard 7x rule and indicates a shift — a sudden, sustained change in assay performance. This systematic error requires investigation (new reagent lot, calibration drift, temperature change).", category: "Quality Control", difficulty: "Medium" },
    { id: 9, question: "Which coagulation test is used to monitor heparin therapy?", options: ["A. Prothrombin time (PT/INR)", "B. Activated partial thromboplastin time (aPTT)", "C. Thrombin time", "D. Fibrinogen level"], correctAnswer: "B", rationale: "The aPTT monitors the intrinsic and common pathways, which are affected by unfractionated heparin. The therapeutic range is typically 1.5-2.5 times the control value. PT/INR monitors warfarin therapy (extrinsic pathway).", category: "Coagulation", difficulty: "Easy" },
    { id: 10, question: "A technologist observes schistocytes and helmet cells on a peripheral blood smear from a patient with elevated LDH and low haptoglobin. What condition is most likely?", options: ["A. Iron deficiency anemia", "B. Microangiopathic hemolytic anemia (MAHA)", "C. Megaloblastic anemia", "D. Thalassemia trait"], correctAnswer: "B", rationale: "Schistocytes (fragmented RBCs) with elevated LDH and decreased haptoglobin indicate intravascular hemolysis. MAHA occurs when RBCs are mechanically sheared by damaged endothelium or fibrin strands, as seen in TTP, HUS, and DIC.", category: "Hematology", difficulty: "Hard" },
  ];
}

function generateImagingQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "When performing an AP chest radiograph, which landmark should the central ray be directed to?", options: ["A. T7 (inferior angle of scapula)", "B. T4 (sternal angle)", "C. T10 (xiphoid process)", "D. T1 (suprasternal notch)"], correctAnswer: "A", rationale: "For an AP or PA chest radiograph, the central ray is directed to T7, which corresponds to the inferior angle of the scapula. This ensures the entire lung field is included on the image from the apices to the costophrenic angles.", category: "Radiographic Positioning", difficulty: "Easy" },
    { id: 2, question: "Which interaction between X-ray photons and matter is primarily responsible for patient dose in diagnostic radiography?", options: ["A. Compton scatter", "B. Photoelectric absorption", "C. Coherent scatter", "D. Pair production"], correctAnswer: "B", rationale: "Photoelectric absorption is responsible for patient dose because the X-ray photon is completely absorbed by the patient's tissues. The photon energy is deposited in the tissue. Compton scatter contributes to both dose and image fog/noise but is the primary source of scatter radiation.", category: "Radiation Physics", difficulty: "Medium" },
    { id: 3, question: "A radiograph of the lateral C-spine must demonstrate which vertebrae to be considered adequate?", options: ["A. C1-C5", "B. C1-C7 including C7-T1 junction", "C. C3-C7", "D. C1-C4 with open mouth for C1-C2"], correctAnswer: "B", rationale: "A lateral cervical spine radiograph must demonstrate all seven cervical vertebrae plus the C7-T1 junction to be diagnostically adequate. Failure to visualize C7-T1 may miss injuries at this common injury site. A swimmer's view may be needed if standard lateral cannot show C7-T1.", category: "Radiographic Positioning", difficulty: "Medium" },
    { id: 4, question: "What is the effect of increasing kVp (while maintaining mAs) on radiographic image contrast?", options: ["A. Increased contrast (shorter scale)", "B. Decreased contrast (longer scale)", "C. No effect on contrast", "D. Increased contrast only at high kVp values"], correctAnswer: "B", rationale: "Increasing kVp produces a longer scale of contrast (more shades of gray, less black-and-white). Higher kVp means more photons undergo Compton interactions, increasing scatter, which reduces contrast. Lower kVp produces short-scale (higher) contrast.", category: "Image Production", difficulty: "Easy" },
    { id: 5, question: "For a CT scan of the abdomen with IV contrast, at what phase timing would you expect maximal enhancement of the liver parenchyma?", options: ["A. Arterial phase (25-30 seconds)", "B. Portal venous phase (60-70 seconds)", "C. Delayed phase (3-5 minutes)", "D. Non-contrast phase"], correctAnswer: "B", rationale: "The liver has dual blood supply (hepatic artery and portal vein), with 75% of blood flow from the portal vein. Maximum liver parenchymal enhancement occurs during portal venous phase (60-70 seconds). Arterial phase optimally shows hypervascular lesions like HCC.", category: "CT Imaging", difficulty: "Hard" },
    { id: 6, question: "What is the maximum permissible annual occupational dose equivalent for a radiation worker's whole body?", options: ["A. 5 mSv (0.5 rem)", "B. 50 mSv (5 rem)", "C. 150 mSv (15 rem)", "D. 500 mSv (50 rem)"], correctAnswer: "B", rationale: "The annual occupational dose limit for whole body is 50 mSv (5 rem) per NCRP Report 116 and ICRP recommendations. Additional limits: lens of eye 150 mSv, extremities 500 mSv. The ALARA principle should always be followed to keep doses well below these limits.", category: "Radiation Protection", difficulty: "Easy" },
    { id: 7, question: "Which artifact appears as alternating bright and dark bands parallel to a high-contrast interface in CT imaging?", options: ["A. Beam hardening artifact", "B. Motion artifact", "C. Ring artifact", "D. Windmill artifact"], correctAnswer: "A", rationale: "Beam hardening artifacts appear as dark streaks or bands near dense structures (like bone or metal) in CT. As the X-ray beam passes through dense material, lower-energy photons are preferentially absorbed, 'hardening' the beam and creating artifacts.", category: "CT Imaging", difficulty: "Medium" },
    { id: 8, question: "For an AP projection of the shoulder, how should the patient's hand be positioned to demonstrate the greater tubercle in profile?", options: ["A. Hand pronated (palm down) — internal rotation", "B. Hand supinated (palm up) — external rotation", "C. Hand in neutral position", "D. Hand across the chest"], correctAnswer: "B", rationale: "External rotation of the humerus (palm supinated/up) brings the greater tubercle into profile laterally. Internal rotation (palm pronated) projects the lesser tubercle in profile. Neutral position shows the greater tubercle slightly superimposed.", category: "Radiographic Positioning", difficulty: "Medium" },
    { id: 9, question: "What is the primary advantage of using a grid in radiography?", options: ["A. Reduces patient dose", "B. Increases image contrast by absorbing scatter radiation", "C. Increases the exposure latitude", "D. Reduces geometric unsharpness"], correctAnswer: "B", rationale: "Grids are placed between the patient and the image receptor to absorb scatter radiation before it reaches the detector. This improves image contrast by reducing fog. However, grids require increased technique (higher mAs), resulting in higher patient dose.", category: "Image Production", difficulty: "Easy" },
    { id: 10, question: "During a barium swallow, a patient is positioned in the RAO position. This position best demonstrates which anatomical structure?", options: ["A. Fundus of the stomach", "B. Esophagus between the spine and heart", "C. Pyloric canal", "D. Duodenal bulb"], correctAnswer: "B", rationale: "The RAO position during a barium swallow moves the esophagus away from the spine, positioning it between the vertebral column and the heart for optimal visualization. This is the standard position for evaluating esophageal motility and mucosal patterns.", category: "Fluoroscopy", difficulty: "Medium" },
  ];
}

function generateSocialWorkQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A social worker is meeting with a 35-year-old client who discloses that she is being physically abused by her partner. The client asks the social worker not to tell anyone. What should the social worker do FIRST?", options: ["A. Report to law enforcement immediately", "B. Assess for immediate safety and develop a safety plan", "C. Respect the client's confidentiality wishes", "D. Contact the partner for a couples session"], correctAnswer: "B", rationale: "The social worker's first priority is assessing immediate safety and creating a safety plan with the client. While respecting autonomy, the social worker has an ethical obligation to ensure the client's safety. Adult domestic violence does not typically require mandatory reporting unless children are involved.", category: "Ethics & Safety", difficulty: "Medium" },
    { id: 2, question: "According to Erik Erikson's psychosocial development theory, what is the primary developmental crisis of adolescence (ages 12-18)?", options: ["A. Industry vs. Inferiority", "B. Identity vs. Role Confusion", "C. Intimacy vs. Isolation", "D. Generativity vs. Stagnation"], correctAnswer: "B", rationale: "Erikson identified Identity vs. Role Confusion as the central crisis of adolescence. Teens explore different roles, values, and identities. Successful resolution leads to a strong sense of self; failure results in role confusion and identity diffusion.", category: "Human Development", difficulty: "Easy" },
    { id: 3, question: "A social worker suspects that a 7-year-old client is being neglected based on the child's poor hygiene, frequent absences from school, and statements about being left alone at night. What is the social worker's legal obligation?", options: ["A. Discuss concerns with the parents first", "B. File a mandatory report with child protective services", "C. Gather more evidence before reporting", "D. Consult with a supervisor before taking action"], correctAnswer: "B", rationale: "Social workers are mandated reporters. When there is reasonable suspicion of child abuse or neglect, the social worker must file a report with child protective services immediately. Waiting to gather more evidence or discussing with parents first could put the child at further risk.", category: "Ethics & Legal", difficulty: "Easy" },
    { id: 4, question: "A client presents with persistent sadness, anhedonia, weight loss, insomnia, fatigue, difficulty concentrating, and passive suicidal ideation lasting for 3 weeks. Using DSM-5 criteria, what is the most appropriate diagnosis?", options: ["A. Persistent Depressive Disorder (Dysthymia)", "B. Major Depressive Disorder, single episode", "C. Adjustment Disorder with Depressed Mood", "D. Bipolar II Disorder, depressive episode"], correctAnswer: "B", rationale: "The client meets DSM-5 criteria for Major Depressive Disorder: 5+ symptoms (depressed mood, anhedonia, weight change, insomnia, fatigue, concentration difficulty, suicidal ideation) lasting ≥2 weeks and causing significant impairment. Dysthymia requires 2+ years duration.", category: "Assessment & Diagnosis", difficulty: "Medium" },
    { id: 5, question: "During a session, a client expresses anger that her therapist is 'just like her mother — never really listening.' From a psychodynamic perspective, this is an example of:", options: ["A. Countertransference", "B. Transference", "C. Projection", "D. Displacement"], correctAnswer: "B", rationale: "Transference occurs when a client unconsciously redirects feelings about significant relationships onto the therapist. The client is transferring feelings about her mother onto the social worker. Countertransference is the therapist's emotional response to the client.", category: "Clinical Theory", difficulty: "Easy" },
    { id: 6, question: "A social worker using Motivational Interviewing (MI) encounters a client who expresses ambivalence about quitting alcohol. Which MI strategy is most appropriate?", options: ["A. Confront the client about the negative consequences of drinking", "B. Explore the discrepancy between current behavior and stated values", "C. Provide psychoeducation about the disease model of addiction", "D. Set immediate abstinence goals for the client"], correctAnswer: "B", rationale: "MI's core principle is developing discrepancy — helping clients see the gap between their current behavior and their stated values/goals. This approach honors client autonomy, avoids confrontation, and elicits the client's own motivation for change (change talk).", category: "Intervention", difficulty: "Medium" },
    { id: 7, question: "A social worker is conducting a biopsychosocial assessment on a new client. Which component addresses the client's family dynamics, social support network, and cultural identity?", options: ["A. Biological component", "B. Psychological component", "C. Social component", "D. Spiritual component"], correctAnswer: "C", rationale: "The social component of the biopsychosocial assessment examines the client's social context: family relationships, support systems, cultural identity, socioeconomic status, community resources, and social determinants of health that impact functioning.", category: "Assessment", difficulty: "Easy" },
    { id: 8, question: "A Tarasoff-type situation exists when a client makes a credible threat to harm an identifiable third party. What is the social worker's ethical and legal obligation?", options: ["A. Maintain strict confidentiality", "B. Warn the identifiable victim and notify authorities", "C. Increase session frequency to monitor the client", "D. Consult with the client about disclosing the threat"], correctAnswer: "B", rationale: "The Tarasoff decision established the 'duty to warn/protect' — when a client poses a serious, credible threat to an identifiable victim, the mental health professional must take reasonable steps to protect the potential victim, which may include warning them and notifying law enforcement.", category: "Ethics & Legal", difficulty: "Hard" },
    { id: 9, question: "A social worker is facilitating a group for survivors of domestic violence. One member becomes highly emotional and begins sharing graphic details of her abuse. Other group members appear distressed. What is the BEST intervention?", options: ["A. Allow the member to continue sharing to process her trauma", "B. Ask the member to stop sharing and change the topic", "C. Validate the member's courage and gently redirect to group safety norms", "D. End the group session early"], correctAnswer: "C", rationale: "The social worker should balance supporting the sharing member while maintaining group safety. Validating courage while redirecting to agreed-upon safety norms protects both the individual and the group. This models healthy boundary-setting.", category: "Group Work", difficulty: "Medium" },
    { id: 10, question: "According to the NASW Code of Ethics, when a social worker's personal values conflict with a client's values, the social worker should:", options: ["A. Refer the client to another provider who shares their values", "B. Prioritize the client's self-determination and avoid imposing personal values", "C. Educate the client about the social worker's perspective", "D. Seek supervision to determine whose values should prevail"], correctAnswer: "B", rationale: "The NASW Code of Ethics emphasizes client self-determination. Social workers should not impose their personal values on clients. If the conflict is significant enough to impair service delivery, consultation and possible referral may be appropriate, but the default is respecting the client's right to make their own choices.", category: "Ethics", difficulty: "Medium" },
  ];
}

function generatePsychotherapyQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A client describes persistent intrusive thoughts about contamination, leading to excessive handwashing that takes 3 hours daily. According to CBT theory, the handwashing represents:", options: ["A. A cognitive distortion", "B. A compulsion (behavioral response to reduce anxiety)", "C. A core belief", "D. An automatic thought"], correctAnswer: "B", rationale: "In OCD, the handwashing is a compulsion — a repetitive behavior performed to reduce anxiety caused by obsessive thoughts (contamination fears). CBT with Exposure and Response Prevention (ERP) targets breaking the obsession-compulsion cycle.", category: "CBT Theory", difficulty: "Easy" },
    { id: 2, question: "During an initial assessment, a psychotherapist learns that a client has experienced childhood sexual abuse, has difficulty trusting others, and presents with emotional dysregulation and dissociative episodes. Which therapeutic approach would be MOST appropriate as a first-line treatment?", options: ["A. Prolonged Exposure therapy immediately", "B. Phase-based trauma treatment (stabilization first)", "C. EMDR intensive protocol", "D. Psychoanalytic free association"], correctAnswer: "B", rationale: "For complex trauma with dissociation and emotional dysregulation, phase-based treatment is recommended. Phase 1 focuses on safety, stabilization, and building coping skills before processing trauma memories (Phase 2). Jumping directly to exposure or trauma processing could retraumatize the client.", category: "Trauma-Informed Care", difficulty: "Hard" },
    { id: 3, question: "A therapist practicing DBT is teaching a client the concept of 'wise mind.' Wise mind represents:", options: ["A. The logical, analytical part of the mind", "B. The emotional, intuitive part of the mind", "C. The integration of emotion mind and reasonable mind", "D. The unconscious mind in psychodynamic theory"], correctAnswer: "C", rationale: "In DBT, Wise Mind is the synthesis of Emotion Mind (driven by feelings) and Reasonable Mind (driven by logic). It represents a balanced state where both emotional experience and rational thought inform decision-making. This is a foundational DBT mindfulness concept.", category: "DBT Theory", difficulty: "Easy" },
    { id: 4, question: "A client in therapy says: 'I failed one exam, so I'm going to fail all my courses and never get a job.' This cognitive distortion is best described as:", options: ["A. Personalization", "B. Catastrophizing and overgeneralization", "C. Emotional reasoning", "D. Mind reading"], correctAnswer: "B", rationale: "This statement combines catastrophizing (imagining the worst possible outcome — never getting a job) with overgeneralization (one failure means all courses will be failed). Identifying these distortions is the first step in cognitive restructuring.", category: "CBT Theory", difficulty: "Easy" },
    { id: 5, question: "According to the stages of change model (Prochaska & DiClemente), a client who acknowledges their alcohol use is problematic but has not yet committed to making changes is in the:", options: ["A. Pre-contemplation stage", "B. Contemplation stage", "C. Preparation stage", "D. Action stage"], correctAnswer: "B", rationale: "In the Contemplation stage, clients are aware of the problem and are considering change but have not committed to action. They weigh the pros and cons. Pre-contemplation involves no awareness or intention to change; Preparation involves planning for imminent change.", category: "Change Theory", difficulty: "Easy" },
    { id: 6, question: "A psychotherapist notices feeling unusually protective and parental toward a young adult client. This emotional reaction is best described as:", options: ["A. Transference", "B. Countertransference", "C. Empathy", "D. Therapeutic alliance"], correctAnswer: "B", rationale: "Countertransference is the therapist's emotional reaction to the client, often based on the therapist's own unresolved issues or the dynamics the client evokes. Recognizing countertransference through supervision is essential for maintaining therapeutic objectivity.", category: "Clinical Practice", difficulty: "Medium" },
    { id: 7, question: "In EMDR therapy, bilateral stimulation (eye movements, tapping, or auditory tones) is believed to facilitate:", options: ["A. Relaxation response through parasympathetic activation", "B. Adaptive information processing and memory reconsolidation", "C. Cognitive restructuring of maladaptive beliefs", "D. Exposure and habituation to traumatic memories"], correctAnswer: "B", rationale: "EMDR's Adaptive Information Processing (AIP) model proposes that bilateral stimulation facilitates processing of traumatic memories by activating the brain's natural healing mechanisms. This allows disturbing memories to be integrated with more adaptive information.", category: "EMDR Theory", difficulty: "Medium" },
    { id: 8, question: "A client in a group therapy session is consistently silent and avoids eye contact. From a group dynamics perspective, the therapist should:", options: ["A. Insist the client participate verbally", "B. Ignore the behavior and focus on active members", "C. Gently invite participation while respecting the client's pace", "D. Process the silence as resistance in the group"], correctAnswer: "C", rationale: "The therapist should create a safe space that invites participation without pressuring. Forcing participation can increase anxiety and resistance. Acknowledging the client's presence and gently offering invitations to share respects individual differences while encouraging growth.", category: "Group Therapy", difficulty: "Medium" },
    { id: 9, question: "A therapist is working with a client who experienced a motor vehicle accident 2 months ago and now avoids driving, has nightmares about the accident, is hypervigilant, and startles easily. How many months of symptoms are required for a DSM-5 diagnosis of PTSD?", options: ["A. 2 weeks", "B. 1 month", "C. 3 months", "D. 6 months"], correctAnswer: "B", rationale: "DSM-5 requires symptoms to be present for at least 1 month for a PTSD diagnosis. Symptoms lasting less than 1 month may qualify for Acute Stress Disorder. At 2 months duration, this client meets the duration criterion for PTSD.", category: "Diagnosis", difficulty: "Easy" },
    { id: 10, question: "A psychotherapist discovers that a new client referred to them is the close friend of another current client. What is the MOST appropriate ethical action?", options: ["A. Accept the client but keep both therapeutic relationships strictly confidential", "B. Decline the referral and provide alternative referrals", "C. Accept only if both clients provide written consent", "D. Accept the client and inform both clients of the situation"], correctAnswer: "B", rationale: "Treating close friends of existing clients creates a dual relationship risk and potential conflicts of interest. The therapist may receive information from one client about the other, creating confidentiality dilemmas. The safest ethical course is to decline and provide appropriate referrals.", category: "Ethics", difficulty: "Medium" },
  ];
}

function generateAddictionsQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A client in early recovery from alcohol use disorder reports tremors, diaphoresis, and anxiety 24 hours after last drink. Using the CIWA-Ar scale, which score range indicates moderate withdrawal requiring medical management?", options: ["A. 0-8", "B. 10-18", "C. 20-30", "D. 31-67"], correctAnswer: "B", rationale: "CIWA-Ar (Clinical Institute Withdrawal Assessment for Alcohol) scores of 10-18 indicate moderate withdrawal. Scores <10 may not require pharmacological intervention. Scores >20 indicate severe withdrawal with risk for seizures and delirium tremens requiring intensive medical management.", category: "Assessment", difficulty: "Medium" },
    { id: 2, question: "According to Prochaska's Transtheoretical Model, which motivational interviewing technique is most appropriate for a client in the pre-contemplation stage?", options: ["A. Developing a detailed relapse prevention plan", "B. Raising awareness and expressing concern without confrontation", "C. Setting abstinence goals and identifying triggers", "D. Reinforcing commitment to change"], correctAnswer: "B", rationale: "In pre-contemplation, clients don't see their substance use as problematic. The MI approach focuses on raising awareness, expressing concern non-judgmentally, and planting seeds of doubt — not pushing for change. Confrontation increases resistance in this stage.", category: "Motivational Interviewing", difficulty: "Easy" },
    { id: 3, question: "A counsellor is working with a client who uses opioids and is considering medication-assisted treatment (MAT). Which medication is a partial opioid agonist used in MAT?", options: ["A. Naltrexone", "B. Methadone", "C. Buprenorphine", "D. Naloxone"], correctAnswer: "C", rationale: "Buprenorphine is a partial opioid agonist — it activates opioid receptors but with a ceiling effect, reducing overdose risk. Methadone is a full agonist. Naltrexone is an antagonist (blocks receptors). Naloxone is a short-acting antagonist used for overdose reversal.", category: "Pharmacology", difficulty: "Medium" },
    { id: 4, question: "During a group counselling session, a client becomes verbally aggressive toward another member. What is the counsellor's FIRST response?", options: ["A. Remove the aggressive client from the group", "B. Allow the group to manage the conflict themselves", "C. Calmly set boundaries and redirect the interaction", "D. End the session immediately"], correctAnswer: "C", rationale: "The counsellor's first response is to de-escalate by calmly setting boundaries ('I need us to speak respectfully to one another'). This maintains safety while keeping the group intact. Removal may be necessary if behavior continues, but redirection is the first intervention.", category: "Group Facilitation", difficulty: "Easy" },
    { id: 5, question: "Which theoretical model views addiction as a chronic, relapsing brain disease characterized by compulsive drug seeking despite harmful consequences?", options: ["A. Moral model", "B. Disease/neurobiological model", "C. Social learning model", "D. Psychodynamic model"], correctAnswer: "B", rationale: "The disease/neurobiological model, supported by NIDA, views addiction as a chronic brain disease involving changes in brain circuits for reward, motivation, memory, and impulse control. This model reduces stigma and supports medical treatment approaches.", category: "Addiction Theory", difficulty: "Easy" },
    { id: 6, question: "A client who has been abstinent from cocaine for 3 months reports intense cravings after driving through their old neighborhood. This is an example of:", options: ["A. Physical dependence", "B. Conditioned cue reactivity (environmental trigger)", "C. Cross-tolerance", "D. Withdrawal symptoms"], correctAnswer: "B", rationale: "Classical conditioning creates associations between drug use and environmental cues (people, places, things). The old neighborhood is a conditioned stimulus that triggers craving (conditioned response). This is why identifying and managing triggers is central to relapse prevention.", category: "Relapse Prevention", difficulty: "Medium" },
    { id: 7, question: "Which screening tool uses the questions: Have you ever felt you should Cut down? Have people Annoyed you by criticizing your drinking? Have you ever felt Guilty? Have you ever had an Eye-opener?", options: ["A. AUDIT", "B. CAGE", "C. DAST-10", "D. SASQ"], correctAnswer: "B", rationale: "The CAGE questionnaire is a brief 4-question screening tool for alcohol problems. Two or more positive responses suggest problematic drinking requiring further assessment. While simple, it has limitations including lower sensitivity in certain populations.", category: "Assessment Tools", difficulty: "Easy" },
    { id: 8, question: "A concurrent disorders counsellor is treating a client with both substance use disorder and major depression. According to best practice guidelines, how should these conditions be treated?", options: ["A. Treat the addiction first, then address depression", "B. Treat depression first, then address addiction", "C. Treat both disorders simultaneously with integrated care", "D. Refer to separate specialists for each condition"], correctAnswer: "C", rationale: "Best practice for concurrent (co-occurring) disorders is integrated treatment — addressing both conditions simultaneously within a coordinated care plan. Sequential treatment (treating one before the other) often leads to poor outcomes because the untreated condition undermines recovery from the other.", category: "Concurrent Disorders", difficulty: "Medium" },
    { id: 9, question: "A harm reduction approach to substance use would include which of the following interventions?", options: ["A. Requiring abstinence before providing any services", "B. Providing clean needle exchange programs and naloxone kits", "C. Refusing to engage clients who are actively using", "D. Mandating 12-step attendance for all clients"], correctAnswer: "B", rationale: "Harm reduction aims to reduce negative consequences of substance use without requiring abstinence. Clean needle exchanges reduce bloodborne pathogen transmission, and naloxone kits prevent opioid overdose deaths. This approach meets clients 'where they are at' on the continuum of change.", category: "Harm Reduction", difficulty: "Easy" },
    { id: 10, question: "An addictions counsellor has been working with a client for 8 months. The client offers tickets to a concert as a thank-you gift. What is the most appropriate ethical response?", options: ["A. Accept the gift to maintain the therapeutic relationship", "B. Decline the gift and explore the meaning of the gesture", "C. Accept the gift but do not attend the same event", "D. Report the client's attempt at boundary violation"], correctAnswer: "B", rationale: "Accepting gifts creates boundary issues and potential dual relationships. The ethical response is to decline respectfully and therapeutically explore the gesture — what does gift-giving mean to the client? This becomes a therapeutic opportunity while maintaining professional boundaries.", category: "Ethics", difficulty: "Medium" },
  ];
}

function generateOtQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "An occupational therapist is evaluating a client who had a stroke affecting the left hemisphere. Which deficit would the OT most likely observe?", options: ["A. Left-sided neglect", "B. Aphasia and right-sided weakness", "C. Spatial-perceptual deficits", "D. Impulsive behavior"], correctAnswer: "B", rationale: "Left hemisphere strokes typically cause aphasia (Broca's or Wernicke's, depending on location) and right-sided motor deficits (contralateral hemiparesis). Left neglect, spatial-perceptual deficits, and impulsivity are more commonly associated with right hemisphere damage.", category: "Neurological Conditions", difficulty: "Medium" },
    { id: 2, question: "According to the Model of Human Occupation (MOHO), which component represents a person's pattern of behavior organized around roles and routines?", options: ["A. Volition", "B. Habituation", "C. Performance capacity", "D. Environment"], correctAnswer: "B", rationale: "In MOHO, Habituation refers to the internalized readiness to exhibit consistent patterns of behavior. It includes habits (automatic behavior patterns) and roles (social positions that shape behavior). Volition involves motivation, and Performance Capacity relates to physical/mental abilities.", category: "OT Theory", difficulty: "Easy" },
    { id: 3, question: "An OT is working with a child diagnosed with autism spectrum disorder who demonstrates difficulty with sensory processing. The child avoids certain textures and covers ears in noisy environments. Using Dunn's Model, this pattern is best described as:", options: ["A. Sensory seeking", "B. Sensory avoiding", "C. Low registration", "D. Sensory sensitivity"], correctAnswer: "B", rationale: "Sensory avoiding behavior (high neurological threshold + active self-regulation strategy) involves actively limiting or avoiding sensory input. The child covers ears (avoiding auditory input) and avoids textures (avoiding tactile input). This differs from sensory sensitivity where the child notices but doesn't actively avoid.", category: "Sensory Processing", difficulty: "Medium" },
    { id: 4, question: "An occupational therapist is fabricating a resting hand splint for a client with rheumatoid arthritis. The wrist should be positioned at:", options: ["A. 20-30 degrees of extension", "B. Neutral (0 degrees)", "C. 15-20 degrees of flexion", "D. Maximum extension tolerated"], correctAnswer: "A", rationale: "A resting hand splint for rheumatoid arthritis positions the wrist in 20-30 degrees of extension (functional position), MCPs in 35-45 degrees of flexion, and IPs in slight flexion. This position maintains joint alignment and reduces deforming forces.", category: "Orthotics", difficulty: "Medium" },
    { id: 5, question: "Which assessment tool measures a client's ability to perform basic activities of daily living (BADLs) such as bathing, dressing, toileting, and feeding?", options: ["A. Canadian Occupational Performance Measure (COPM)", "B. FIM (Functional Independence Measure)", "C. Allen Cognitive Level Screen", "D. Interest Checklist"], correctAnswer: "B", rationale: "The FIM measures functional independence across 18 items in self-care, sphincter management, transfers, locomotion, communication, and social cognition. Each item is scored 1-7 (total dependence to complete independence). COPM is a client-centered measure of occupational performance and satisfaction.", category: "Assessment", difficulty: "Easy" },
    { id: 6, question: "An OT is teaching a client with a C6 spinal cord injury to dress independently. What is the highest level of assistance expected for lower body dressing?", options: ["A. Independent with adaptive equipment", "B. Supervision only", "C. Minimal assistance", "D. Maximum assistance"], correctAnswer: "A", rationale: "A client with C6 SCI has wrist extension (tenodesis grip) and can typically achieve independence with lower body dressing using adaptive equipment (dressing stick, sock aid, long-handled shoehorn) and modified techniques (side-lying, momentum-based strategies).", category: "Spinal Cord Injury", difficulty: "Hard" },
    { id: 7, question: "An occupational therapist is providing cognitive rehabilitation for a client with traumatic brain injury. Which cognitive function should be addressed FIRST in the treatment hierarchy?", options: ["A. Executive functioning", "B. Memory", "C. Attention", "D. Problem-solving"], correctAnswer: "C", rationale: "According to the cognitive rehabilitation hierarchy, attention is the foundation for all higher cognitive functions. Without adequate attention, a client cannot effectively process, encode, or retrieve information. The hierarchy progresses: attention → memory → executive function → problem-solving.", category: "Cognitive Rehabilitation", difficulty: "Medium" },
    { id: 8, question: "A home health OT is conducting an environmental assessment for a 78-year-old client with a history of falls. Which modification is MOST important for fall prevention?", options: ["A. Installing a stairlift", "B. Removing throw rugs and improving lighting", "C. Adding a hospital bed", "D. Installing a whole-house intercom system"], correctAnswer: "B", rationale: "Environmental hazards — particularly throw rugs and poor lighting — are the most common modifiable risk factors for falls in the elderly. Removing loose rugs eliminates tripping hazards, and improved lighting (especially night lights and hallway lighting) helps with depth perception and obstacle avoidance.", category: "Home Modification", difficulty: "Easy" },
    { id: 9, question: "An OT working in pediatrics is planning intervention for a 5-year-old with fine motor delays who cannot button clothing or use scissors effectively. Which grasp pattern is needed for scissors use?", options: ["A. Palmar grasp", "B. Lateral pinch", "C. Tripod grasp", "D. Cylindrical grasp"], correctAnswer: "C", rationale: "Scissors use requires a dynamic tripod grasp pattern — thumb, index, and middle fingers work together with isolated finger movements. Children typically develop sufficient precision and hand strength for scissors around ages 4-5. Fine motor activities should progress from gross to refined movements.", category: "Pediatric OT", difficulty: "Easy" },
    { id: 10, question: "In a mental health setting, an OT is using the Allen Cognitive Level Screen (ACLS) and determines a client is functioning at Level 4. What does this level indicate about the client's functional abilities?", options: ["A. Cannot perform any self-care tasks safely", "B. Can perform familiar routine tasks with cueing but cannot problem-solve novel situations", "C. Fully independent in all ADLs and IADLs", "D. Can follow simple one-step commands only"], correctAnswer: "B", rationale: "Allen Level 4 (Goal-directed actions) indicates the person can perform familiar, routine tasks but has difficulty with new learning, problem-solving, and anticipating consequences. They may need cueing for changes in routine and cannot safely manage complex tasks like medication management or finances.", category: "Mental Health OT", difficulty: "Hard" },
  ];
}

function generatePharmacyTechQuestions(): AuthorityQuestion[] {
  return [
    { id: 1, question: "A prescription reads: 'Amoxicillin 500mg PO TID x 10 days.' How many capsules should be dispensed?", options: ["A. 10 capsules", "B. 20 capsules", "C. 30 capsules", "D. 40 capsules"], correctAnswer: "C", rationale: "TID means three times daily. 3 capsules/day × 10 days = 30 capsules. Understanding prescription abbreviations is fundamental for pharmacy technicians. Always verify the calculation before dispensing.", category: "Prescription Processing", difficulty: "Easy" },
    { id: 2, question: "Which of the following medications is a Schedule II controlled substance requiring special handling and storage?", options: ["A. Alprazolam (Xanax)", "B. Oxycodone (OxyContin)", "C. Tramadol (Ultram)", "D. Gabapentin (Neurontin)"], correctAnswer: "B", rationale: "Oxycodone is a Schedule II controlled substance — high abuse potential with accepted medical use. Schedule II drugs cannot be refilled and require a new prescription each time. Alprazolam is Schedule IV, tramadol is Schedule IV, and gabapentin is Schedule V in some states.", category: "Controlled Substances", difficulty: "Easy" },
    { id: 3, question: "A pharmacy technician is compounding a prescription requiring 250 mL of a 0.9% sodium chloride solution. How many grams of NaCl are needed?", options: ["A. 0.9 grams", "B. 2.25 grams", "C. 9 grams", "D. 22.5 grams"], correctAnswer: "B", rationale: "0.9% means 0.9 grams per 100 mL. For 250 mL: (0.9g/100mL) × 250 mL = 2.25 grams. Percentage concentration calculations are fundamental pharmacy math skills tested on the PTCB exam.", category: "Pharmacy Calculations", difficulty: "Medium" },
    { id: 4, question: "Which auxiliary label should be placed on a prescription for metronidazole (Flagyl)?", options: ["A. Take with food", "B. Avoid alcohol", "C. May cause drowsiness", "D. Take on empty stomach"], correctAnswer: "B", rationale: "Metronidazole causes a disulfiram-like reaction with alcohol — severe nausea, vomiting, flushing, headache, and tachycardia. Patients must avoid all alcohol (including in medications and mouthwash) during treatment and 48 hours after completing the course.", category: "Pharmacology", difficulty: "Easy" },
    { id: 5, question: "A medication has a NDC number of 12345-6789-01. What does the middle segment (6789) identify?", options: ["A. The manufacturer", "B. The specific drug product", "C. The package size", "D. The lot number"], correctAnswer: "B", rationale: "The NDC (National Drug Code) has three segments: first (labeler/manufacturer), middle (product — drug name, strength, dosage form), and last (package size/type). The 10-digit NDC is essential for accurate medication identification and billing.", category: "Pharmacy Operations", difficulty: "Medium" },
    { id: 6, question: "Which of the following insulins has the longest duration of action?", options: ["A. Lispro (Humalog)", "B. Regular (Humulin R)", "C. NPH (Humulin N)", "D. Glargine (Lantus)"], correctAnswer: "D", rationale: "Insulin glargine (Lantus) is a long-acting basal insulin with a duration of approximately 24 hours and no peak. Lispro is rapid-acting (3-5 hrs), Regular is short-acting (6-8 hrs), and NPH is intermediate-acting (12-18 hrs).", category: "Pharmacology", difficulty: "Medium" },
    { id: 7, question: "According to USP <797>, what is the beyond-use date (BUD) for a low-risk compounded sterile preparation stored at room temperature?", options: ["A. 12 hours", "B. 24 hours", "C. 48 hours", "D. 14 days"], correctAnswer: "C", rationale: "Under USP <797> guidelines, low-risk CSPs stored at controlled room temperature have a BUD of 48 hours. If refrigerated (2-8°C), the BUD extends to 14 days. If frozen (-25 to -10°C), the BUD is 45 days. These limits ensure sterility.", category: "Sterile Compounding", difficulty: "Hard" },
    { id: 8, question: "A patient brings in a new prescription that has a drug interaction with their current medication profile. What should the pharmacy technician do?", options: ["A. Counsel the patient about the interaction", "B. Refuse to fill the prescription", "C. Alert the pharmacist to review the interaction", "D. Contact the prescriber directly"], correctAnswer: "C", rationale: "Pharmacy technicians cannot provide clinical counseling or make clinical decisions about drug interactions. The technician must alert the pharmacist, who will evaluate the interaction and determine appropriate action (counsel patient, contact prescriber, or adjust therapy).", category: "Pharmacy Law", difficulty: "Easy" },
    { id: 9, question: "Which of the following represents a tall man lettering pair used to prevent medication errors?", options: ["A. aspirin / acetaminophen", "B. hydrOXYzine / hydrALAZINE", "C. amoxicillin / ampicillin", "D. lisinopril / losartan"], correctAnswer: "B", rationale: "Tall man lettering emphasizes the differing parts of look-alike/sound-alike drug names to prevent dispensing errors. HydrOXYzine (antihistamine) vs. hydrALAZINE (antihypertensive) is a classic tall man lettering pair. This ISMP strategy has been shown to reduce medication errors.", category: "Patient Safety", difficulty: "Easy" },
    { id: 10, question: "A pharmacy technician is preparing a TPN (total parenteral nutrition) solution in a laminar airflow workbench. Which direction does air flow in a horizontal laminar airflow hood?", options: ["A. From the ceiling down toward the work surface", "B. From the HEPA filter toward the operator (front to back)", "C. From the operator toward the HEPA filter (back to front)", "D. Air circulates in a circular pattern"], correctAnswer: "B", rationale: "In a horizontal laminar airflow hood, HEPA-filtered air flows from the back of the hood (where the filter is) toward the operator. This pushes contaminants away from the critical site. The operator should never block airflow between the HEPA filter and the work area.", category: "Sterile Compounding", difficulty: "Medium" },
  ];
}

